mapper.select:
SELECT datetime
, temperature
, humidity
, speed
, direction
, rain
, sunlight
, pm25
, pm10
FROM ${tableName}
WHERE DATE_FORMAT(dateTime, '%Y-%m-%d %H:%i:00') >= #{startDateTime}
  AND DATE_FORMAT(dateTime, '%Y-%m-%d %H:%i:59') <= #{endDateTime}
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM ${tableName}
WHERE DATE_FORMAT(dateTime, '%Y-%m-%d %H:%i:00') >= #{startDateTime}
  AND DATE_FORMAT(dateTime, '%Y-%m-%d %H:%i:59') <= #{endDateTime}
